static inline const UCDProperty* lookup_unicode_property(const char* name, int kind) {
    for (size_t i = 0; i < sizeof(UCD_PROPERTIES)/sizeof(UCD_PROPERTIES[0]); i++) {
        if (UCD_PROPERTIES[i].kind == kind && strcmp(UCD_PROPERTIES[i].name, name) == 0) return &UCD_PROPERTIES[i];
    }
    return NULL;
}

