static inline uint32_t unicode_casefold(uint32_t cp) {
    int left = 0, right = sizeof(UCD_CASE_FOLD)/sizeof(CaseFoldMapping) - 1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (UCD_CASE_FOLD[mid].from == cp) return UCD_CASE_FOLD[mid].to;
        if (UCD_CASE_FOLD[mid].from < cp) left = mid + 1;
        else right = mid - 1;
    }
    return cp;
}

